#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define IDX2(arr, row, col) ((arr)[(row) * BLOCK_SIZE + (col)])

__kernel void
lud_diagonal(__global float *m,
             __local float *shadow,
             int matrix_dim,
             int offset)
{
    int tx = (int)get_local_id(0);
    int i, j;
    int array_offset = offset * matrix_dim + offset;

    for (i = 0; i < BLOCK_SIZE; i++) {
        IDX2(shadow, i, tx) = m[array_offset + tx];
        array_offset += matrix_dim;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        if (tx > i) {
            for (j = 0; j < i; j++)
                IDX2(shadow, tx, i) -= IDX2(shadow, tx, j) * IDX2(shadow, j, i);
            IDX2(shadow, tx, i) /= IDX2(shadow, i, i);
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (tx > i) {
            for (j = 0; j < i + 1; j++)
                IDX2(shadow, i + 1, tx) -= IDX2(shadow, i + 1, j) * IDX2(shadow, j, tx);
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
        m[array_offset + tx] = IDX2(shadow, i, tx);
        array_offset += matrix_dim;
    }
}

__kernel void
lud_perimeter(__global float *m,
              __local float *dia,
              __local float *peri_row,
              __local float *peri_col,
              int matrix_dim,
              int offset)
{
    int tx = (int)get_local_id(0);
    int bx = (int)get_group_id(0);
    int i, j, array_offset;
    int idx;

    if (tx < BLOCK_SIZE) {
        idx = tx;

        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE / 2; i++) {
            IDX2(dia, i, idx) = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            IDX2(peri_row, i, idx) = m[array_offset + (bx + 1) * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }
    } else {
        idx = tx - BLOCK_SIZE;

        array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
        for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
            IDX2(dia, i, idx) = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            IDX2(peri_col, i, idx) = m[array_offset + idx];
            array_offset += matrix_dim;
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        idx = tx;
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++)
                IDX2(peri_row, i, idx) -= IDX2(dia, i, j) * IDX2(peri_row, j, idx);
        }
    } else {
        idx = tx - BLOCK_SIZE;
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++)
                IDX2(peri_col, idx, i) -= IDX2(peri_col, idx, j) * IDX2(dia, j, i);
            IDX2(peri_col, idx, i) /= IDX2(dia, i, i);
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        idx = tx;
        array_offset = (offset + 1) * matrix_dim + offset;
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[array_offset + (bx + 1) * BLOCK_SIZE + idx] = IDX2(peri_row, i, idx);
            array_offset += matrix_dim;
        }
    } else {
        idx = tx - BLOCK_SIZE;
        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            m[array_offset + idx] = IDX2(peri_col, i, idx);
            array_offset += matrix_dim;
        }
    }
}

__kernel void
lud_internal(__global float *m,
             __local float *peri_row,
             __local float *peri_col,
             int matrix_dim,
             int offset)
{
    int tx = (int)get_local_id(0);
    int ty = (int)get_local_id(1);
    int bx = (int)get_group_id(0);
    int by = (int)get_group_id(1);
    int i;
    float sum;

    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

    IDX2(peri_row, ty, tx) = m[(offset + ty) * matrix_dim + global_col_id + tx];
    IDX2(peri_col, ty, tx) = m[(global_row_id + ty) * matrix_dim + offset + tx];

    barrier(CLK_LOCAL_MEM_FENCE);

    sum = 0.0f;
    for (i = 0; i < BLOCK_SIZE; i++)
        sum += IDX2(peri_col, ty, i) * IDX2(peri_row, i, tx);

    m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
}
